1;;; javier_pacheco utilities.el --- Some useful utilities -*- lexical-binding: t; -*- 2(defun +org--insert-item (direction) 3 (let ((context (org-element-lineage 4 (org-element-context) 5 &#39;(table table-row headline inlinetask item plain-list) 6 t))) 7 (pcase (org-element-type context) 8 ;; Add a new list item (carrying over checkboxes if necessary) 9 ((or `item `plain-list) 10 (let ((orig-point (point))) 11 ;; Position determines where org-insert-todo-heading and `org-insert-item&#39; 12 ;; insert the new list item. 13 (if (eq direction &#39;above) 14 (org-beginning-of-item) 15 (end-of-line)) 16 (let* ((ctx-item? (eq &#39;item (org-element-type context))) 17 (ctx-cb (org-element-property :contents-begin context)) 18 ;; Hack to handle edge case where the point is at the 19 ;; beginning of the first item 20 (beginning-of-list? (and (not ctx-item?) 21 (= ctx-cb orig-point))) 22 (item-context (if beginning-of-list? 23 (org-element-context) 24 context)) 25 ;; Horrible hack to handle edge case where the 26 ;; line of the bullet is empty 27 (ictx-cb (org-element-property :contents-begin item-context)) 28 (empty? (and (eq direction &#39;below) 29 ;; in case contents-begin is nil, or contents-begin 30 ;; equals the position end of the line, the item is 31 ;; empty 32 (or (not ictx-cb) 33 (= ictx-cb 34 (1+ (point)))))) 35 (pre-insert-point (point))) 36 ;; Insert dummy content, so that `org-insert-item&#39; 37 ;; inserts content below this item 38 (when empty? 39 (insert &#34; &#34;)) 40 (org-insert-item (org-element-property :checkbox context)) 41 ;; Remove dummy content 42 (when empty? 43 (delete-region pre-insert-point (1+ pre-insert-point)))))) 44 ;; Add a new table row 45 ((or `table `table-row) 46 (pcase direction 47 (&#39;below (save-excursion (org-table-insert-row t)) 48 (org-table-next-row)) 49 (&#39;above (save-excursion (org-shiftmetadown)) 50 (+org/table-previous-row)))) 51 52 ;; Otherwise, add a new heading, carrying over any todo state, if 53 ;; necessary. 54 (_ 55 (let ((level (or (org-current-level) 1))) 56 ;; I intentionally avoid `org-insert-heading&#39; and the like because they 57 ;; impose unpredictable whitespace rules depending on the cursor 58 ;; position. It&#39;s simpler to express this command&#39;s responsibility at a 59 ;; lower level than work around all the quirks in org&#39;s API. 60 (pcase direction 61 (`below 62 (let (org-insert-heading-respect-content) 63 (goto-char (line-end-position)) 64 (org-end-of-subtree) 65 (insert &#34;
&#34; (make-string level ?*) &#34; &#34;))) 66 (`above 67 (org-back-to-heading) 68 (insert (make-string level ?*) &#34; &#34;) 69 (save-excursion (insert &#34;
&#34;)))) 70 (run-hooks &#39;org-insert-heading-hook) 71 (when-let* ((todo-keyword (org-element-property :todo-keyword context)) 72 (todo-type (org-element-property :todo-type context))) 73 (org-todo 74 (cond ((eq todo-type &#39;done) 75 ;; Doesn&#39;t make sense to create more &#34;DONE&#34; headings 76 (car (+org-get-todo-keywords-for todo-keyword))) 77 (todo-keyword) 78 (&#39;todo))))))) 79 80 (when (org-invisible-p) 81 (org-show-hidden-entry)) 82 (when (and (bound-and-true-p evil-local-mode) 83 (not (evil-emacs-state-p))) 84 (evil-insert 1)))) 85 86;;;###autoload 87(defun +org/insert-item-below (count) 88 &#34;Inserts a new heading, table cell or item below the current one.&#34; 89 (interactive &#34;p&#34;) 90 (dotimes (_ count) (+org--insert-item &#39;below))) 91 92;;;###autoload 93(defun +org/insert-item-above (count) 94 &#34;Inserts a new heading, table cell or item above the current one.&#34; 95 (interactive &#34;p&#34;) 96 (dotimes (_ count) (+org--insert-item &#39;above))) 97 98 99(defun org-make-olist (arg) 100 (interactive &#34;P&#34;) 101 (let ((n (or arg 1))) 102 (when (region-active-p) 103 (setq n (count-lines (region-beginning) 104 (region-end))) 105 (goto-char (region-beginning))) 106 (dotimes (i n) 107 (beginning-of-line) 108 (insert (concat (number-to-string (1+ i)) &#34;. &#34;)) 109 (forward-line)))) Highlight yanked text This function describes itself so&hellip;
1(defun meain/evil-yank-advice (orig-fn beg end &amp;rest args) 2 (pulse-momentary-highlight-region beg end &#39;mode-line-active) 3 (apply orig-fn beg end args)) 4(advice-add &#39;evil-yank :around &#39;meain/evil-yank-advice) Replace &lsquo;-&rsquo; with &lsquo;•&rsquo;. 1(defun jp/org-font-setup () 2 ;; Replace list hyphen with dot 3 (font-lock-add-keywords &#39;org-mode 4 &#39;((&#34;^ *\([-]\) &#34; 5 (0 (prog1 () (compose-region (match-beginning 1) (match-end 1) &#34;•&#34;))))))) 6 7(jp/org-font-setup) Custom_id. 1;;;; org-id 2(declare-function org-id-add-location &#34;org&#34;) 3(declare-function org-with-point-at &#34;org&#34;) 4(declare-function org-entry-get &#34;org&#34;) 5(declare-function org-id-new &#34;org&#34;) 6(declare-function org-entry-put &#34;org&#34;) 7 8;; Copied from this article (with minor tweaks from my side): 9;; https://writequit.org/articles/emacs-org-mode-generate-ids.html. 10(defun jp/org--id-get (&amp;optional pom create prefix) 11 &#34;Get the CUSTOM_ID property of the entry at point-or-marker POM. 12If POM is nil, refer to the entry at point. If the entry does 13not have an CUSTOM_ID, the function returns nil. However, when 14CREATE is non nil, create a CUSTOM_ID if none is present already. 15PREFIX will be passed through to `org-id-new&#39;. In any case, the 16CUSTOM_ID of the entry is returned.&#34; 17 (org-with-point-at pom 18 (let ((id (org-entry-get nil &#34;CUSTOM_ID&#34;))) 19 (cond 20 ((and id (stringp id) (string-match \S- id)) 21 id) 22 (create 23 (setq id (org-id-new (concat prefix &#34;h&#34;))) 24 (org-entry-put pom &#34;CUSTOM_ID&#34; id) 25 (org-id-add-location id (format &#34;%s&#34; (buffer-file-name (buffer-base-buffer)))) 26 id))))) 27 28(declare-function org-map-entries &#34;org&#34;) 29 30;;;###autoload 31(defun jp/org-id-headlines () 32 &#34;Add missing CUSTOM_ID to all headlines in current file.&#34; 33 (interactive) 34 (org-map-entries 35 (lambda () (jp/org--id-get (point) t)))) 36 37;;;###autoload 38(defun jp/org-id-headline () 39 &#34;Add missing CUSTOM_ID to headline at point.&#34; 40 (interactive) 41 (jp/org--id-get (point) t)) Add ID&rsquo;s to headers - Org roam. 1(defun jp/org-id-store-link-for-headers () 2 &#34;Run `org-id-store-link&#39; for each header in the current buffer.&#34; 3 (interactive) 4 (save-excursion 5 (goto-char (point-min)) 6 (while (re-search-forward org-heading-regexp nil t) 7 (org-id-store-link)))) Toggle org-emphasis-markers 1(defun jp/org-toggle-emphasis-markers (&amp;optional arg) 2 &#34;Toggle emphasis markers and display a message.&#34; 3 (interactive &#34;p&#34;) 4 (let ((markers org-hide-emphasis-markers) 5 (msg &#34;&#34;)) 6 (when markers 7 (setq-local org-hide-emphasis-markers nil) 8 (setq msg &#34;Emphasis markers are now visible.&#34;)) 9 (unless markers 10 (setq-local org-hide-emphasis-markers t) 11 (setq msg &#34;Emphasis markers are now hidden.&#34;)) 12 (message &#34;%s&#34; msg) 13 (when arg 14 (font-lock-fontify-buffer)))) Insert Org&rsquo;s files to Outlook. Export file to clipboard. 1(defun export-org-email () 2 &#34;Export the current email org buffer and copy it to the 3clipboard&#34; 4 (interactive) 5 (let ((org-export-show-temporary-export-buffer nil) 6 (org-html-head (org-email-html-head))) 7 (org-html-export-as-html) 8 (with-current-buffer &#34;*Org HTML Export*&#34; 9 (kill-new (buffer-string))) 10 (message &#34;HTML copied to clipboard&#34;))) 11(global-set-key (kbd &#34;C-c C-x C-e&#34;) &#39;export-org-email) Add some CSS to the file. 1(defun org-email-html-head () 2 &#34;Create the header with CSS for use with email&#34; 3 (concat 4 &#34;&lt;style type=\&#34;text/css\&#34;&gt;
&#34; 5 &#34;&lt;!--/*--&gt;&lt;![CDATA[/*&gt;&lt;!--*/
&#34; 6 (with-temp-buffer 7 (insert-file-contents 8 &#34;~/.emacs.d/src/css/org2outlook.css&#34;) 9 (buffer-string)) 10 &#34;/*]]&gt;*/--&gt;
