&#34;)) Org TODO auto update. 1(defun org-todo-if-needed (state) 2 &#34;Change header state to STATE unless the current item is in STATE already.&#34; 3 (unless (string-equal (org-get-todo-state) state) 4 (org-todo state))) 5 6(defun ct/org-summary-todo-cookie (n-done n-not-done) 7 &#34;Switch header state to DONE when all subentries are DONE, to TODO when none are DONE, and to DOING otherwise&#34; 8 (let (org-log-done org-log-states) ; turn off logging 9 (org-todo-if-needed (cond ((= n-done 0) 10 &#34;TODO&#34;) 11 ((= n-not-done 0) 12 &#34;DONE&#34;) 13 (t 14 &#34;DOING&#34;))))) 15(add-hook &#39;org-after-todo-statistics-hook #&#39;ct/org-summary-todo-cookie) 16 17(defun ct/org-summary-checkbox-cookie () 18 &#34;Switch header state to DONE when all checkboxes are ticked, to TODO when none are ticked, and to DOING otherwise&#34; 19 (let (beg end) 20 (unless (not (org-get-todo-state)) 21 (save-excursion 22 (org-back-to-heading t) 23 (setq beg (point)) 24 (end-of-line) 25 (setq end (point)) 26 (goto-char beg) 27 ;; Regex group 1: %-based cookie 28 ;; Regex group 2 and 3: x/y cookie 29 (if (re-search-forward &#34;\[\([0-9]*%\)\]\|\[\([0-9]*\)/\([0-9]*\)\]&#34; 30 end t) 31 (if (match-end 1) 32 ;; [xx%] cookie support 33 (cond ((equal (match-string 1) &#34;100%&#34;) 34 (org-todo-if-needed &#34;DONE&#34;)) 35 ((equal (match-string 1) &#34;0%&#34;) 36 (org-todo-if-needed &#34;TODO&#34;)) 37 (t 38 (org-todo-if-needed &#34;DOING&#34;))) 39 ;; [x/y] cookie support 40 (if (&gt; (match-end 2) (match-beginning 2)) ; = if not empty 41 (cond ((equal (match-string 2) (match-string 3)) 42 (org-todo-if-needed &#34;DONE&#34;)) 43 ((or (equal (string-trim (match-string 2)) &#34;&#34;) 44 (equal (match-string 2) &#34;0&#34;)) 45 (org-todo-if-needed &#34;TODO&#34;)) 46 (t 47 (org-todo-if-needed &#34;DOING&#34;))) 48 (org-todo-if-needed &#34;DOING&#34;)))))))) 49(add-hook &#39;org-checkbox-statistics-hook #&#39;ct/org-summary-checkbox-cookie) Org-buffer-scratchpad. 1(defun new-scratch-pad () 2 &#34;Create a new org-mode buffer for random stuff.&#34; 3 (interactive) 4 (progn 5 (let ((buffer (generate-new-buffer &#34;Org-scratch-buffer&#34;))) 6 (switch-to-buffer buffer) 7 (setq buffer-offer-save t) 8 (org-mode) 9 (olivetti-mode t)))) Toggle buffers. 1;; Toggle *scratch* buffer. 2(defun toggle-scratch-buffer () 3 &#34;Toggle the *scratch* buffer&#34; 4 (interactive) 5 (if (string= (buffer-name) &#34;*scratch*&#34;) 6 (bury-buffer) 7 (switch-to-buffer (get-buffer-create &#34;*scratch*&#34;)))) 8 9(defun toggle-org-buffer () 10 &#34;Toggle the Org-scratch-buffer buffer&#34; 11 (interactive) 12 (if (equal (buffer-name (current-buffer)) &#34;Org-scratch-buffer&#34;) 13 (if (one-window-p t) 14 (switch-to-buffer (other-buffer)) 15 (delete-window)) 16 (if (get-buffer &#34;Org-scratch-buffer&#34;) 17 (if (get-buffer-window &#34;Org-scratch-buffer&#34;) 18 (progn 19 (bury-buffer &#34;Org-scratch-buffer&#34;) 20 (delete-window (get-buffer-window &#34;Org-scratch-buffer&#34;))) 21 (switch-to-buffer &#34;Org-scratch-buffer&#34;)) 22 (new-scratch-pad)))) 23 24;; Toggle *eshell* buffer. 25(defun toggle-eshell-buffer () 26 &#34;Toggle the *eshell* buffer&#34; 27 (interactive) 28 (if (string= (buffer-name) &#34;*eshell*&#34;) 29 (bury-buffer) 30 (switch-to-buffer (get-buffer-create &#34;*eshell*&#34;)))) Doc at point. 1(defun my-show-doc-or-describe-symbol () 2 &#34;Show LSP UI doc if LSP is active, otherwise describe symbol at point.&#34; 3 (interactive) 4 (if (bound-and-true-p lsp-mode) 5 (lsp-ui-doc-glance) 6 (describe-symbol-at-point))) Duplicate &amp; move up/down lines. 1(defun duplicate-line () 2 (interactive) 3 (let ((line-text (thing-at-point &#39;line t))) 4 (save-excursion 5 (move-end-of-line 1) 6 (newline) 7 (insert line-text))) 8 (forward-line 1)) 9 10(defun move-line-up () 11 (interactive) 12 (when (not (= (line-number-at-pos) 1)) 13 (transpose-lines 1) 14 (forward-line -2))) 15 16(defun move-line-down () 17 (interactive) 18 (forward-line 1) 19 (when (not (= (line-number-at-pos) (point-max))) 20 (transpose-lines 1)) 21 (forward-line -1)) Hide passwords in org files. 1;; Define a custom face for the highlight 2(defface my-highlight-face 3 &#39;((t (:foreground &#34;gray&#34;))) ; Change &#34;red&#34; to your desired color 4 &#34;Face for highlighting !!word!! patterns.&#34;) 5 6;; Function to replace matched text with asterisks 7(defun replace-with-asterisks (limit) 8 &#34;Replace !!word!! with asterisks up to LIMIT.&#34; 9 (while (re-search-forward &#34;!!\(.*?\)!!&#34; limit t) 10 (let* ((match (match-string 1)) 11 (start (match-beginning 0)) 12 (end (match-end 0)) 13 (asterisks (make-string (length match) ?*))) 14 (add-text-properties start end `(display ,asterisks face my-highlight-face))))) 15 16;; Add custom keyword for font-lock in org-mode 17(defun my/org-mode-custom-font-lock () 18 &#34;Add custom font-lock keywords for org-mode.&#34; 19 (font-lock-add-keywords nil 20 &#39;((replace-with-asterisks)))) 21 22;; Hook the custom font-lock configuration into org-mode 23(add-hook &#39;org-mode-hook &#39;my/org-mode-custom-font-lock) Help at point. 1(defun describe-symbol-at-point () 2 &#34;Display the documentation of the symbol at point, if it exists.&#34; 3 (interactive) 4 (let ((symbol (symbol-at-point))) 5 (if symbol 6 (cond 7 ((fboundp symbol) (describe-function symbol)) 8 ((boundp symbol) (describe-variable symbol)) 9 (t (message &#34;No documentation found for symbol at point: %s&#34; symbol))) 10 (message &#34;No symbol at point&#34;)))) fz-themes 1(defun custom-jp-themes (&amp;optional theme-dir) 2 3 (defun custom-jp-themes (&amp;optional theme-dir) 4 &#34;Return a list of custom themes from a specified directory. 5Search the directory for files named FOO-theme.el, and return a list of FOO symbols, 6excluding the &#39;default&#39; theme and any internal themes. 7 8If THEME-DIR is nil, it defaults to `~/.emacs.d/lisp/jp-themes/&#39;.&#34; 9 (let ((suffix &#34;-theme\.el\&#39;&#34;) 10 (directory (or theme-dir &#34;~/.emacs.d/lisp/jp-themes/&#34;)) 11 themes) 12 ;; Ensure the directory exists 13 (when (file-directory-p directory) 14 ;; Iterate over all theme files in the directory 15 (dolist (file (directory-files directory nil suffix)) 16 (let ((theme (intern (substring file 0 (string-match-p suffix file))))) 17 ;; Add to the list if it&#39;s valid, and exclude Emacs built-in &#34;default&#34; theme 18 (and (not (eq theme &#39;default)) ;; Ensure &#34;default&#34; is excluded 19 (not (memq theme themes)) ;; Avoid duplicates 20 (push theme themes))))) 21 (nreverse themes))) 22 23 (defcustom fz-themes nil 24 &#34;List of themes (symbols or regexps) to be presented for selection. 25nil shows all `custom-available-themes&#39;.&#34; 26 :type &#39;(repeat (choice symbol regexp))) 27 28 (defun fz-theme (theme) 29 &#34;Disable current themes and enable THEME from `fz-themes`. 30 31The command supports previewing the currently selected theme.&#34; 32 (interactive 33 (list 34 (let* ((regexp (consult--regexp-filter 35 (mapcar (lambda (x) (if (stringp x) x (format &#34;\`%s\&#39;&#34; x))) 36 fz-themes))) 37 (avail-themes (seq-filter 38 (lambda (x) (string-match-p regexp (symbol-name x))) 39 (custom-jp-themes))) ;; Only use themes from custom-jp-themes 40 (saved-theme (car custom-enabled-themes))) 41 (consult--read 42 (mapcar #&#39;symbol-name avail-themes) 43 :prompt &#34;Theme: &#34; 44 :require-match t 45 :category &#39;theme 46 :history &#39;consult--theme-history 47 :lookup (lambda (selected &amp;rest _) 48 (setq selected (and selected (intern-soft selected))) 49 (or (and selected (car (memq selected avail-themes))) 50 saved-theme)) 51 :state (lambda (action theme) 52 (pcase action 53 (&#39;return (fz-theme (or theme saved-theme))) 54 ((and &#39;preview (guard theme)) (fz-theme theme)))) 55 :default (symbol-name (or saved-theme &#39;default)))))) 56 (when (eq theme &#39;default) (setq theme nil)) 57 (unless (eq theme (car custom-enabled-themes)) 58 (mapc #&#39;disable-theme custom-enabled-themes) 59 (when theme 60 (if (custom-theme-p theme) 61 (enable-theme theme) 62 (load-theme theme :no-confirm))))) Custom functions. 1;; Open files in the lisp folder 2(require &#39;find-lisp) 3(defun open-lisp-and-org-files () 4 &#34;Open a Lisp or Org file from ~/.emacs.d/lisp directory, including subfolders.&#34; 5 (interactive) 6 (let* ((directory &#34;~/.emacs.d/lisp&#34;) 7 (el-files (find-lisp-find-files directory &#34;.*\.el$&#34;)) 8 (org-files (find-lisp-find-files directory &#34;.*\.org$&#34;)) 9 (all-files (append el-files org-files)) 10 (file (completing-read &#34;Select file: &#34; all-files nil t))) 11 (find-file file))) 12 13;; Follow urls in the buffer 14(defun list-and-open-url-in-buffer () 15 &#34;List all URLs in the current buffer, display them in the minibuffer, and open a selected URL in the browser.&#34; 16 (interactive) 17 (let (urls) 18 (save-excursion 19 (goto-char (point-min)) 20 (while (re-search-forward &#34;\(http\|https\|ftp\|file\|mailto\):[^ 	
]+&#34; nil t) 21 (push (match-string 0) urls))) 22 (if urls 23 (let ((url (completing-read &#34;Select URL to open: &#34; (reverse urls) nil t))) 24 (browse-url url)) 25 (message &#34;No URLs found in the buffer.&#34;)))) 26 27;; Export org files to pdf using tectonic 28(defun org-export-to-latex-and-compile-with-tectonic () 29 &#34;Export the current Org file to LaTeX, then compile with tectonic using shell-escape.&#34; 30 (interactive) 31 (let* ((org-file (buffer-file-name)) 32 (tex-file (concat (file-name-sans-extension org-file) &#34;.tex&#34;)) 33 (tectonic-command (concat &#34;tectonic -Z shell-escape &#34; tex-file))) 34 ;; Export Org file to LaTeX 35 (org-latex-export-to-latex) 36 ;; Run tectonic command in a temporary buffer to avoid displaying the output 37 (with-temp-buffer 38 (shell-command tectonic-command (current-buffer))) 39 (message &#34;Compiled %s to PDF with Tectonic.&#34; tex-file))) 40 41(global-set-key (kbd &#34;C-c e l&#34;) &#39;org-export-to-latex-and-compile-with-tectonic) 42 43;; Update my web-page 44(defun publish-my-blog () 45 &#34;Export all subtrees with Hugo, then run the publish blog script within Emacs and display a success message in the minibuffer.&#34; 46 (interactive) 47 (let ((commit-msg (read-string &#34;Enter commit message: &#34;))) 48 ;; Export all subtrees with Hugo 49 (org-hugo-export-wim-to-md :all-subtrees) 50 ;; Run the publish script 51 (let ((process (start-process-shell-command 52 &#34;publish-blog&#34; ; Process name 53 &#34;*publish-blog-output*&#34; ; Output buffer 54 (format &#34;~/webdev/jpachecoxyz.github.io/hugo/publish.sh \&#34;%s\&#34;&#34; commit-msg)))) ; Run the script with the commit message 55 ;; Set up the process sentinel to check the process status 56 (set-process-sentinel 57 process 58 (lambda (process event) 59 (when (string= event &#34;finished
&#34;) 60 (message &#34;jpacheco.xyz was correctly updated!&#34;))))))) 61 62(global-set-key (kbd &#34;C-c u b&#34;) &#39;publish-my-blog) 63 64;; Search roam 65(defun jp/search-roam () 66 &#34;Run consult-ripgrep on the org roam directory&#34; 67 (interactive) 68 (consult-ripgrep org-roam-directory nil)) 69(global-set-key (kbd &#34;C-c n s&#34;) &#39;jp/search-roam) 70 71(defun jp/yt-shorts-timer () 72 (interactive) 73 (org-timer-set-timer &#34;55s&#34;)) 74(global-set-key (kbd &#34;&lt;f4&gt;&#34;) &#39;jp/yt-shorts-timer) Linux Python Avoid SSL verification when installing packages through pip. I have some issues with the firewall in one of my jobs, so in order to be able to install python packages through pip we need to skip the SSL verification with the following flags.
